'use client'
import { cn } from '@cascivo/core'
import type { CSSProperties, HTMLAttributes } from 'react'
import styles from './section.module.css'

type SpaceStep = 1 | 2 | 3 | 4 | 5 | 6 | 8 | 10 | 12

export interface SectionProps extends HTMLAttributes<HTMLElement> {
  /** Max inline size of the inner content wrapper. */
  width?: 'content' | 'wide' | 'full'
  /** Internal stack gap between child elements. */
  gap?: SpaceStep
  className?: string | undefined
}

export function Section({
  width = 'content',
  gap = 8,
  className,
  style,
  children,
  ...props
}: SectionProps) {
  const maxInlineSize = width === 'content' ? '72rem' : width === 'wide' ? '90rem' : 'none'
  return (
    <section
      className={cn(styles['section'], className)}
      style={{
        ['--_max' as string]: maxInlineSize,
        ['--_gap' as string]: `var(--cascivo-space-${gap})`,
        ...(style as CSSProperties | undefined),
      }}
      {...props}
    >
      <div className={styles['inner']}>{children}</div>
    </section>
  )
}

@layer cascivo.component {
  .section {
    padding-block: var(--cascivo-space-12);
    padding-inline: var(--cascivo-space-4);
    container-type: inline-size;
  }

  .inner {
    max-inline-size: var(--_max, 72rem);
    margin-inline: auto;
    display: flex;
    flex-direction: column;
    gap: var(--_gap, var(--cascivo-space-8));
  }
}
